mapper.select:
SELECT ra.* FROM release_assets ra

    INNER JOIN software_types st ON ra.software_type_id = st.id


    AND ra.published = #{published}

        AND (ra.middleware_name LIKE CONCAT('%',#{keyword},'%') OR ra.description LIKE CONCAT('%',#{keyword},'%') OR ra.original_file_name LIKE CONCAT('%',#{keyword},'%'))


        AND st.category = #{category}


        AND ra.platform = #{platform}


ORDER BY ra.created_at DESC
